import{_ as a,o as r,c as e,S as o}from"./chunks/framework.C6RQlTYc.js";const p=JSON.parse('{"title":"神经网络","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_4-neural_network.md","filePath":"直击概念/17ai/s_ai_4-neural_network.md","lastUpdated":1778207238000}'),i={name:"直击概念/17ai/s_ai_4-neural_network.md"};function n(l,t,d,s,h,u){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="神经网络" tabindex="-1">神经网络 <a class="header-anchor" href="#神经网络" aria-label="Permalink to &quot;神经网络&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>神经网络（Neural Network）是深度学习的核心计算模型，其设计灵感来源于<strong>生物神经系统</strong>。它由大量相互连接的<strong>神经元</strong>（节点）组成，通过调整连接权重来学习数据中的模式。</p><p>一个基本的前馈神经网络由三层组成：</p><ul><li><strong>输入层（Input Layer）</strong>：接收原始数据</li><li><strong>隐藏层（Hidden Layers）</strong>：进行特征提取和变换（可有多层）</li><li><strong>输出层（Output Layer）</strong>：产生最终预测结果</li></ul><h2 id="核心组件" tabindex="-1">核心组件 <a class="header-anchor" href="#核心组件" aria-label="Permalink to &quot;核心组件&quot;">​</a></h2><h3 id="神经元" tabindex="-1">神经元 <a class="header-anchor" href="#神经元" aria-label="Permalink to &quot;神经元&quot;">​</a></h3><p>每个神经元执行两步操作：</p><ol><li><strong>加权求和</strong>：z = w₁x₁ + w₂x₂ + ... + wₙxₙ + b（w 为权重，b 为偏置）</li><li><strong>激活函数</strong>：a = f(z)，引入非线性</li></ol><h3 id="激活函数-activation-function" tabindex="-1">激活函数（Activation Function） <a class="header-anchor" href="#激活函数-activation-function" aria-label="Permalink to &quot;激活函数（Activation Function）&quot;">​</a></h3><p>为神经网络引入<strong>非线性变换能力</strong>，否则多层网络等价于单层线性模型。</p><table><thead><tr><th>函数</th><th>公式</th><th>特点</th></tr></thead><tbody><tr><td>Sigmoid</td><td>σ(x) = 1/(1+e⁻ˣ)</td><td>输出 0~1，易饱和导致梯度消失</td></tr><tr><td>Tanh</td><td>tanh(x)</td><td>输出 -1~1，零中心化，仍会饱和</td></tr><tr><td>ReLU</td><td>max(0, x)</td><td>计算简单，缓解梯度消失，最常用</td></tr><tr><td>GELU</td><td>x·Φ(x)</td><td>Transformer 中广泛使用，比 ReLU 更平滑</td></tr><tr><td>SwiGLU</td><td></td><td>Llama 等模型的标配激活函数</td></tr></tbody></table><h3 id="权重-weight-和偏置-bias" tabindex="-1">权重（Weight）和偏置（Bias） <a class="header-anchor" href="#权重-weight-和偏置-bias" aria-label="Permalink to &quot;权重（Weight）和偏置（Bias）&quot;">​</a></h3><ul><li><strong>权重</strong>：控制输入信号的重要程度，是模型学习的核心参数</li><li><strong>偏置</strong>：允许神经元在输入全为零时也能激活</li></ul><h3 id="前向传播-forward-propagation" tabindex="-1">前向传播（Forward Propagation） <a class="header-anchor" href="#前向传播-forward-propagation" aria-label="Permalink to &quot;前向传播（Forward Propagation）&quot;">​</a></h3><p>数据从输入层逐层计算，经过每一层的加权求和和激活函数，最终在输出层得到预测结果。</p><h2 id="为什么神经网络能工作" tabindex="-1">为什么神经网络能工作 <a class="header-anchor" href="#为什么神经网络能工作" aria-label="Permalink to &quot;为什么神经网络能工作&quot;">​</a></h2><p>神经网络通过<strong>反向传播算法</strong>不断调整权重，使预测结果逐渐逼近真实值。这个过程的本质是在高维空间中寻找一个损失函数的最小值点。</p><p>通用近似定理指出：一个包含单隐藏层的前馈网络，只要有足够多的神经元，就能以任意精度逼近任意连续函数。</p><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>为什么需要激活函数？没有它会发生什么？</li><li>ReLU 解决了什么问题？有什么缺点？</li><li>神经网络的&quot;深度&quot;和&quot;宽度&quot;分别指什么？哪个更重要？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://en.wikipedia.org/wiki/Neural_network_(machine_learning)" target="_blank" rel="noreferrer">Neural Network - Wikipedia</a></li><li><a href="https://www.youtube.com/playlist?list=PLZHQObOWTQDNU6R1_67000Dx_ZCJB-3pi" target="_blank" rel="noreferrer">3Blue1Brown: Neural Networks</a></li></ul>',23)])])}const g=a(i,[["render",n]]);export{p as __pageData,g as default};
